def calculateStatistics(scores_json):
    try:
        scores = json.loads(scores_json)
        if not isinstance(scores, list):
            raise ValueError("Input JSON must be a list of scores.")
        cleaned_scores = [float(score) for score in scores if isinstance(score, (int, float))]
        if not cleaned_scores:
            raise ValueError("No valid numeric scores found in the input.")
        scores_mean = mean(cleaned_scores)
        scores_median = median(cleaned_scores)
        try:
            scores_mode = mode(cleaned_scores)
        except StatisticsError:
            scores_mode = None  # No unique mode
        return {"mean": scores_mean, "median": scores_median, "mode": scores_mode}
    except (json.JSONDecodeError, ValueError) as e:
        return {"error": str(e)}
