fn calculate_stats(numbers: &[i32]) -> (i32, i32, f64) {
    if numbers.is_empty() {
        return (0, 0, 0.0);
    }

    let mut min = numbers[0];
    let mut max = numbers[0];
    let mut sum = 0;

    for &number in numbers.iter() {
        if number < min {
            min = number;
        }
        if number > max {
            max = number;
        }
        sum += number;
    }

    let average = sum as f64 / numbers.len() as f64;
    (min, max, average)
