import java.util.*;

public class NetworkAnalyzer {
    public List<Integer> analyzeNetworkConnectivity(Map<Integer, List<Integer>> graph) {
        List<Integer> criticalNodes = new ArrayList<>();
        for (Integer node : graph.keySet()) {
            if (isCriticalNode(graph, node)) {
                criticalNodes.add(node);
            }
        }
        return criticalNodes;
    }

    private boolean isCriticalNode(Map<Integer, List<Integer>> graph, Integer node) {
        Map<Integer, List<Integer>> modifiedGraph = new HashMap<>();
        for (Map.Entry<Integer, List<Integer>> entry : graph.entrySet()) {
            if (!entry.getKey().equals(node)) {
                modifiedGraph.put(entry.getKey(), new ArrayList<>(entry.getValue()));
                modifiedGraph.get(entry.getKey()).remove(node);
            }
        }
        return countComponents(modifiedGraph) > 1;
    }

    private int countComponents(Map<Integer, List<Integer>> graph) {
        Set<Integer> visited = new HashSet<>();
        int components = 0;
        for (Integer node : graph.keySet()) {
            if (!visited.contains(node)) {
                components++;
                dfs(node, graph, visited);
            }
        }
        return components;
    }

    private void dfs(Integer node, Map<Integer, List<Integer>> graph, Set<Integer> visited) {
        Stack<Integer> stack = new Stack<>();
        stack.push(node);
        while (!stack.isEmpty()) {
            Integer current = stack.pop();
            if (visited.add(current)) {
                for (Integer neighbor : graph.getOrDefault(current, Collections.emptyList())) {
                    if (!visited.contains(neighbor)) {
                        stack.push(neighbor);
                    }
                }
            }
        }
    }
}
