fn calculate_divisors(n: i32) -> Vec<i32> {
    if n <= 0 {
        return Vec::new();
    }
    let mut divisors = Vec::new();
    let limit = (n as f64).sqrt() as i32;
    for i in 1..=limit {
        if n % i == 0 {
            divisors.push(i);
            if i != n / i {
                divisors.push(n / i);
            }
        }
    }
    divisors.sort();
    divisors
}
