#include <iostream>
#include <vector>
#include <unordered_map>
#include <set>
#include <limits>

std::vector<int> findShortestPath(const std::unordered_map<int, std::vector<std::pair<int, int>>>& graph, int start, int end) {
    std::unordered_map<int, int> dist;
    std::unordered_map<int, int> prev;
    std::set<std::pair<int, int>> q;

    for (const auto& [node, _] : graph) {
        dist[node] = std::numeric_limits<int>::max();
    }

    dist[start] = 0;
    q.insert({0, start});

    while (!q.empty()) {
        int u = q.begin()->second;
        q.erase(q.begin());

        if (u == end) {
            break;
        }

        for (const auto& [v, weight] : graph.at(u)) {
            int alt = dist[u] + weight;
            if (alt < dist[v]) {
                q.erase({dist[v], v});
                dist[v] = alt;
                prev[v] = u;
                q.insert({dist[v], v});
            }
        }
    }

    std::vector<int> path;
    for (int at = end; prev.count(at); at = prev[at]) {
        path.push_back(at);
    }

    if (!path.empty() || start == end) {
        path.push_back(start);
    }

    std::reverse(path.begin(), path.end());
    return path;
}
